[
  {
    "text": "The dual impedance-matching condition accurately predicts optimal bath bandwidths for spectral densities with power-law frequency dependence, including sub-Ohmic (s = 0.5) and super-Ohmic (s = 3) cases.",
    "topic": "Extended spectral density coverage"
  },
  {
    "text": "Constructive multimode interference persists when conductor mode frequencies deviate randomly up to ±5% from uniform spacing.",
    "topic": "Robustness to mode spacing inhomogeneity"
  },
  {
    "text": "The transmission window width at half maximum decreases linearly with increasing bath temperature when the thermal energy is less than the mode splitting.",
    "topic": "Finite-temperature scaling"
  },
  {
    "text": "Introducing a weak Duffing-type anharmonicity of 1% of the harmonic frequency does not shift the optimal bath bandwidth by more than the prediction uncertainty of the analytical model.",
    "topic": "Anharmonicity sensitivity"
  }
]
